parameters.jsCode:
// Find the transcript file from recording files
const meeting = $input.item.json;
const recordingFiles = meeting.recording_files || [];

// Find VTT transcript
const transcript = recordingFiles.find(f => f.file_type === 'TRANSCRIPT' || f.file_extension === 'VTT');
const videoFile = recordingFiles.find(f => f.file_type === 'MP4');

if (!transcript) {
  // Skip meetings with no transcript
  return [];
}

return [{
  json: {
    meeting_id: meeting.uuid,
    topic: meeting.topic,
    start_time: meeting.start_time,
    duration: meeting.duration,
    host_email: meeting.host_email,
    participants: meeting.participant_count,
    transcript_url: transcript.download_url,
    recording_url: videoFile ? videoFile.play_url : null,
    share_url: meeting.share_url
  }
}];

// Parse VTT transcript to clean plain text
const vttContent = $input.item.json.data || $input.item.json.body || '';
const meetingData = $input.all()[0].json;

// Strip VTT formatting: timestamps, WEBVTT header, sequence numbers
const cleanText = vttContent
  .split('\n')
  .filter(line => {
    // Remove WEBVTT header
    if (line.startsWith('WEBVTT')) return false;
    // Remove timestamp lines (00:00:01.000 --> 00:00:05.000)
    if (line.match(/^\d{2}:\d{2}:\d{2}/)) return false;
    // Remove sequence numbers
    if (line.match(/^\d+$/)) return false;
    // Remove empty lines
    if (line.trim() === '') return false;
    return true;
  })
  .join(' ')
  .replace(/\s+/g, ' ')
  .trim();

// Truncate to ~12000 chars to stay within GPT context
const truncated = cleanText.length > 12000 
  ? cleanText.substring(0, 12000) + '... [transcript truncated]'
  : cleanText;

return [{
  json: {
    ...meetingData,
    transcript_text: truncated,
    transcript_length: cleanText.length
  }
}];

values.content:
You are an expert meeting analyst. Analyze the following meeting transcript and produce a structured summary in clean HTML format.

Meeting: {{ $json.topic }}
Date: {{ $json.start_time }}
Duration: {{ $json.duration }} minutes
Participants: {{ $json.participants }}

Return ONLY a JSON object with this exact structure:
{
  "summary": "2-3 sentence overview of the meeting",
  "decisions": ["decision 1", "decision 2"],
  "action_items": [
    {"task": "task description", "owner": "person name or Unknown", "deadline": "date or TBD"}
  ],
  "follow_up_required": true/false,
  "follow_up_notes": "what needs to happen next",
  "key_topics": ["topic 1", "topic 2", "topic 3"]
}

TRANSCRIPT:
{{ $json.transcript_text }}

parameters.jsCode:
// Merge GPT output with meeting metadata
const meetingData = $input.all()[0].json;
let summary;

try {
  const content = meetingData.message?.content || meetingData.choices?.[0]?.message?.content || '{}';
  summary = typeof content === 'string' ? JSON.parse(content) : content;
} catch(e) {
  summary = {
    summary: 'Summary generation failed - please review transcript manually.',
    decisions: [],
    action_items: [],
    follow_up_required: false,
    follow_up_notes: '',
    key_topics: []
  };
}

// Build HTML email body
const actionItemsHtml = summary.action_items?.map(item => 
  `<tr><td style="padding:8px;border-bottom:1px solid #eee">${item.task}</td><td style="padding:8px;border-bottom:1px solid #eee">${item.owner}</td><td style="padding:8px;border-bottom:1px solid #eee">${item.deadline}</td></tr>`
).join('') || '<tr><td colspan="3" style="padding:8px">No action items identified</td></tr>';

const decisionsHtml = summary.decisions?.map(d => `<li style="margin-bottom:6px">${d}</li>`).join('') || '<li>No decisions recorded</li>';

const emailHtml = `
<div style="font-family:Arial,sans-serif;max-width:680px;margin:0 auto">
  <div style="background:#1C1618;padding:20px 28px;border-radius:4px 4px 0 0">
    <h1 style="color:#F9F7F8;font-size:20px;margin:0;font-weight:400">Meeting Summary</h1>
    <p style="color:#847278;font-size:13px;margin:6px 0 0">${meetingData.topic} &nbsp;·&nbsp; ${new Date(meetingData.start_time).toLocaleDateString('en-US', {weekday:'long',year:'numeric',month:'long',day:'numeric'})} &nbsp;·&nbsp; ${meetingData.duration} min</p>
  </div>
  <div style="background:#F9F7F8;padding:24px 28px;border:1px solid #e8e0e3">
    <p style="color:#36262C;line-height:1.6;margin-top:0">${summary.summary}</p>

    <h3 style="color:#1C1618;font-size:14px;text-transform:uppercase;letter-spacing:0.12em;margin-bottom:10px">Key Decisions</h3>
    <ul style="color:#36262C;padding-left:18px;margin-bottom:24px">${decisionsHtml}</ul>

    <h3 style="color:#1C1618;font-size:14px;text-transform:uppercase;letter-spacing:0.12em;margin-bottom:10px">Action Items</h3>
    <table style="width:100%;border-collapse:collapse;margin-bottom:24px">
      <thead><tr style="background:#F2EEF0">
        <th style="padding:8px;text-align:left;font-size:12px;color:#847278">Task</th>
        <th style="padding:8px;text-align:left;font-size:12px;color:#847278">Owner</th>
        <th style="padding:8px;text-align:left;font-size:12px;color:#847278">Deadline</th>
      </tr></thead>
      <tbody>${actionItemsHtml}</tbody>
    </table>

    ${summary.follow_up_required ? `<div style="background:#fff8e7;border-left:3px solid #e6a817;padding:12px 16px;margin-bottom:24px"><strong>Follow-up Required:</strong> ${summary.follow_up_notes}</div>` : ''}

    <p style="color:#847278;font-size:12px;margin-bottom:0">Generated by <strong>Curcible MeetCore™</strong> &nbsp;·&nbsp; <a href="${meetingData.share_url}" style="color:#6A4858">View Recording</a></p>
  </div>
</div>`;

return [{
  json: {
    ...meetingData,
    summary_data: summary,
    email_html: emailHtml,
    email_subject: `Meeting Summary: ${meetingData.topic} — ${new Date(meetingData.start_time).toLocaleDateString()}`
  }
}];

